import React from "react";
import { Outlet, Link, useLocation } from "react-router-dom";

const AdminLayout = () => {
  const location = useLocation();

  const navItems = [
    { name: "Tổng quan", path: "/admin/dashboard", icon: "📊" },
    { name: "Quản lý sản phẩm", path: "/admin/products", icon: "🛍️" },
    { name: "Quản lý đơn hàng", path: "/admin/orders", icon: "📦" },
    { name: "Quản lý danh mục", path: "/admin/categories", icon: "🗂️" },
    { name: "Quản lý người dùng", path: "/admin/users", icon: "👤" },
  ];

  const currentPage = location.pathname.replace("/admin/", "").toUpperCase();
  const isDashboard = location.pathname === "/admin/dashboard";

  return (
    <div className="flex min-h-screen font-sans bg-background text-[14px] leading-relaxed">
      {/* Sidebar */}
     <aside className="sidebar w-60 fixed left-0 top-0 bottom-0 border-r border-accent/20 shadow-soft">
  <div className="p-5 flex items-center gap-3 border-b border-accent/10">
    <div className="w-10 h-10 rounded-full bg-primary text-white flex items-center justify-center font-bold shadow">
      A
    </div>
    <div>
      <p className="text-sm font-semibold text-dark">Admin</p>
      <p className="text-xs text-primary">DTP Flower Shop</p>
    </div>
  </div>

  <nav className="mt-4 flex flex-col gap-2">
    {navItems.map((item) => (
      <Link
        key={item.path}
        to={item.path}
        className={`flex items-center gap-3 px-4 py-2 rounded-md text-sm font-medium transition-all duration-200 ${
          location.pathname === item.path
            ? "bg-primary text-white shadow-soft"
            : "text-dark hover:bg-primary/10 hover:text-primary"
        }`}
      >
        <span>{item.icon}</span>
        {item.name}
      </Link>
    ))}
  </nav>

  <div className="mt-auto p-4">
    <a
      href="/"
      className="block text-center bg-accent text-light py-2 rounded-md font-semibold hover:bg-primary transition"
    >
      🌸 Xem trang web
    </a>
  </div>
</aside>


      {/* Main content */}
      <main
        className={`flex-1 ml-52 p-6 overflow-y-auto transition-colors duration-300 ${
          isDashboard ? "bg-background" : "bg-background/80"
        }`}
      >
        <div className="flex justify-between items-center mb-5">
          <h1
            className={`text-lg font-semibold ${
              isDashboard ? "text-secondary" : "text-secondary/80"
            }`}
          >
            {currentPage || "DASHBOARD"}
          </h1>
        </div>

        <div
          className={`p-5 rounded-lg shadow-md min-h-[70vh] bg-white/90 border border-accent/20`}
        >
          <Outlet />
        </div>
      </main>
    </div>
  );
};

export default AdminLayout;
